{
    "level": "A1–A2",
    "intro": "Для майбутнього часу з <strong>to be</strong> ми беремо <strong>will be</strong>. Форма однакова з усіма підметами.",
    "rules": [
        {
            "label": "will be",
            "color": "emerald",
            "text": "З <strong>I / you / he / she / it / we / they</strong> модель одна й та сама: <strong>will be</strong>.",
            "example": "I will be at home. / They will be ready."
        },
        {
            "label": "won't be",
            "color": "blue",
            "text": "Заперечення = <strong>will not be</strong> або <strong>won't be</strong>.",
            "example": "She won't be late."
        },
        {
            "label": "Will ... be?",
            "color": "amber",
            "text": "У питаннях винеси <strong>will</strong> на початок і залиш <strong>be</strong> після підмета.",
            "example": "Will he be here? / Will they be ready?"
        }
    ]
}

{
    "title": "1. Форма will be",
    "intro": "Це одна з найпростіших майбутніх моделей: всі підмети беруть ту саму форму.",
    "items": [
        {
            "label": "Усі підмети",
            "title": "will be",
            "subtitle": "I will be there. / She will be tired. / They will be ready."
        },
        {
            "label": "Короткі форми",
            "title": "'ll be",
            "subtitle": "I'll be late. / She'll be here soon."
        },
        {
            "label": "Заперечення",
            "title": "will not be / won't be",
            "subtitle": "We won't be at home."
        },
        {
            "label": "Схема",
            "title": "Subject + will be",
            "subtitle": "He will be busy. / We will be in Paris."
        }
    ]
}

{
    "title": "2. Заперечення",
    "intro": "Заперечення утворюється дуже просто: <strong>will not be</strong> або <strong>won't be</strong>.",
    "rows": [
        {
            "en": "I will be at home.",
            "ua": "I won't be at home.",
            "note": "won't = will not"
        },
        {
            "en": "She will be tired.",
            "ua": "She will not be tired.",
            "note": "Повна форма звучить чіткіше."
        },
        {
            "en": "They will be late.",
            "ua": "They won't be late.",
            "note": "Форма одна для всіх підметів."
        }
    ],
    "warning": "📌 Після <strong>will</strong> бери <strong>be</strong>, а не <strong>am / is / are</strong>."
}

{
    "title": "3. Питання",
    "sections": [
        {
            "label": "Will + subject + be",
            "color": "emerald",
            "description": "У загальному питанні починай з <strong>will</strong>, а потім став підмет і <strong>be</strong>.",
            "examples": [
                {
                    "en": "Will he be here tomorrow?",
                    "ua": "Чи буде він тут завтра?"
                },
                {
                    "en": "Will they be ready by noon?",
                    "ua": "Чи будуть вони готові до полудня?"
                }
            ]
        },
        {
            "label": "Питання з питальним словом",
            "color": "blue",
            "description": "Після <strong>where / when / why / who</strong> також йде <strong>will + subject + be</strong>.",
            "examples": [
                {
                    "en": "Where will you be tonight?",
                    "ua": "Де ти будеш сьогодні ввечері?"
                },
                {
                    "en": "Why will she be late?",
                    "ua": "Чому вона запізниться?"
                }
            ]
        },
        {
            "label": "Не забувай про be",
            "color": "amber",
            "description": "Не забувай <strong>be</strong>: саме воно робить майбутню форму <strong>to be</strong> повною.",
            "examples": [
                {
                    "en": "She will be at home. → Will she be at home?",
                    "ua": "У питанні <strong>be</strong> залишається після підмета."
                },
                {
                    "en": "Will they be busy later?",
                    "ua": "Форма одна і та сама з усіма підметами."
                }
            ]
        }
    ]
}

{
    "title": "4. Короткі відповіді",
    "intro": "У короткій відповіді ми повторюємо <strong>will</strong> або <strong>won't</strong>, а не <strong>be</strong>.",
    "rows": [
        {
            "en": "Will you be at home tonight?",
            "ua": "Yes, I will. / No, I won't.",
            "note": "Після Will you...? відповідаємо I will / I won't."
        },
        {
            "en": "Will she be ready soon?",
            "ua": "Yes, she will. / No, she won't.",
            "note": "will → she will / she won't"
        },
        {
            "en": "Will they be there tomorrow?",
            "ua": "Yes, they will. / No, they won't.",
            "note": "will → they will / they won't"
        }
    ],
    "warning": "📌 У коротких відповідях повторюй <strong>will / won't</strong>, а не <strong>be</strong>."
}

{
    "title": "5. Типові помилки",
    "items": [
        {
            "label": "Помилка 1",
            "color": "rose",
            "title": "Ставити am / is / are після will.",
            "wrong": "❌ He will is late.",
            "right": "✅ <span class=\"font-mono\">He will be late.</span>"
        },
        {
            "label": "Помилка 2",
            "color": "amber",
            "title": "Пропускати be у питанні.",
            "wrong": "❌ Will they ready?",
            "right": "✅ <span class=\"font-mono\">Will they be ready?</span>"
        },
        {
            "label": "Помилка 3",
            "color": "sky",
            "title": "Плутати future of to be з теперішньою формою.",
            "wrong": "❌ We are late tomorrow.",
            "right": "✅ <span class=\"font-mono\">We will be late tomorrow.</span>"
        }
    ]
}

